struct CommandBuilder {
  typedef Command Table;
  ::flatbuffers::FlatBufferBuilder &fbb_;
  ::flatbuffers::uoffset_t start_;
  void add_command_id(uint64_t command_id) {
    fbb_.AddElement<uint64_t>(Command::VT_COMMAND_ID, command_id, 0);
  }
  void
  add_type_type(tt::runtime::distributed::flatbuffer::CommandType type_type) {
    fbb_.AddElement<uint8_t>(Command::VT_TYPE_TYPE,
                             static_cast<uint8_t>(type_type), 0);
  }
  void add_type(::flatbuffers::Offset<void> type) {
    fbb_.AddOffset(Command::VT_TYPE, type);
  }
  explicit CommandBuilder(::flatbuffers::FlatBufferBuilder &_fbb) : fbb_(_fbb) {
    start_ = fbb_.StartTable();
  }
  ::flatbuffers::Offset<Command> Finish() {
    const auto end = fbb_.EndTable(start_);
    auto o = ::flatbuffers::Offset<Command>(end);
    return o;
  }
};

inline ::flatbuffers::Offset<Command>
CreateCommand(::flatbuffers::FlatBufferBuilder &_fbb, uint64_t command_id = 0,
              tt::runtime::distributed::flatbuffer::CommandType type_type =
                  tt::runtime::distributed::flatbuffer::CommandType::NONE,
              ::flatbuffers::Offset<void> type = 0) {
  CommandBuilder builder_(_fbb);
  builder_.add_command_id(command_id);
  builder_.add_type(type);
  builder_.add_type_type(type_type);
  return builder_.Finish();
}

