inline const tt::runtime::distributed::flatbuffer::Command *
GetCommand(const void *buf) {
  return ::flatbuffers::GetRoot<tt::runtime::distributed::flatbuffer::Command>(
      buf);
}

inline const tt::runtime::distributed::flatbuffer::Command *
GetSizePrefixedCommand(const void *buf) {
  return ::flatbuffers::GetSizePrefixedRoot<
      tt::runtime::distributed::flatbuffer::Command>(buf);
}

inline const char *CommandIdentifier() { return "DCMD"; }

inline bool CommandBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(buf, CommandIdentifier());
}

inline bool SizePrefixedCommandBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(buf, CommandIdentifier(), true);
}

inline bool VerifyCommandBuffer(::flatbuffers::Verifier &verifier) {
  return verifier.VerifyBuffer<tt::runtime::distributed::flatbuffer::Command>(
      CommandIdentifier());
}

inline bool VerifySizePrefixedCommandBuffer(::flatbuffers::Verifier &verifier) {
  return verifier
      .VerifySizePrefixedBuffer<tt::runtime::distributed::flatbuffer::Command>(
          CommandIdentifier());
}

inline const char *CommandExtension() { return "distcmd"; }

inline void FinishCommandBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<tt::runtime::distributed::flatbuffer::Command> root) {
  fbb.Finish(root, CommandIdentifier());
}

inline void FinishSizePrefixedCommandBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<tt::runtime::distributed::flatbuffer::Command> root) {
  fbb.FinishSizePrefixed(root, CommandIdentifier());
}

inline std::unique_ptr<tt::runtime::distributed::flatbuffer::CommandT>
UnPackCommand(const void *buf,
              const ::flatbuffers::resolver_function_t *res = nullptr) {
  return std::unique_ptr<tt::runtime::distributed::flatbuffer::CommandT>(
      GetCommand(buf)->UnPack(res));
}

inline std::unique_ptr<tt::runtime::distributed::flatbuffer::CommandT>
UnPackSizePrefixedCommand(
    const void *buf, const ::flatbuffers::resolver_function_t *res = nullptr) {
  return std::unique_ptr<tt::runtime::distributed::flatbuffer::CommandT>(
      GetSizePrefixedCommand(buf)->UnPack(res));
}

